const BY_ID = new Map<string, EquipmentSet>(EQUIPMENT_SETS.map((s) => [s.id, s]));

export function getEquipmentSet(id: string): EquipmentSet | undefined {
  return BY_ID.get(id);
}

// Seed helper: returns a fresh Record<string, EquipmentSet> cloned from the
// static catalog. Used by demoSeed and v5→v6 storage migration. Deep-clones
// the items array so callers never share references with the module-level
// EQUIPMENT_SETS.
export function seedEquipmentSets(): Record<string, EquipmentSet> {
  const out: Record<string, EquipmentSet> = {};
  for (const s of EQUIPMENT_SETS) {
    out[s.id] = {
      ...s,
      items: s.items.map((it) => ({ ...it })),
    };
  }
  return out;
}
